// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join;

import static org.junit.jupiter.api.Assertions.assertAll;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class ScopedEvaluationLedgerTest {

	@Test
	void releasedCandidateKeysDoNotRemainLive() {
		ScopedEvaluationLedger ledger = new ScopedEvaluationLedger();
		ledger.candidateRetained(1);
		ledger.candidateRetained(2);

		assertFalse(ledger.containsJoin(3, 1, 2, "hash"));
		assertTrue(ledger.recordJoin(3, 1, 2, "hash"));
		assertTrue(ledger.containsJoin(3, 1, 2, "hash"));
		assertFalse(ledger.containsPredicate(4, 1, 0, "filter"));
		assertTrue(ledger.recordPredicate(4, 1, 0, "filter"));
		assertEquals(2, ledger.liveEntryCount());

		ledger.candidateReleased(1);

		assertAll(
				() -> assertFalse(ledger.containsJoin(3, 1, 2, "hash"),
						"A released monotonic input ID can never suppress later join work"),
				() -> assertFalse(ledger.containsPredicate(4, 1, 0, "filter"),
						"A released monotonic input ID can never suppress later predicate work"),
				() -> assertEquals(0, ledger.liveEntryCount(),
						"Released candidate keys must not accumulate for the lifetime of the search"));
	}

	@Test
	void releasedJoinKeysReusePrimitiveTableCapacity() {
		ScopedEvaluationLedger ledger = new ScopedEvaluationLedger();
		ledger.candidateRetained(1);
		for (int index = 0; index < 24; index++) {
			int rightCandidateId = index + 2;
			ledger.candidateRetained(rightCandidateId);
			assertTrue(ledger.recordJoin(1_000 + index, 1, rightCandidateId, "hash"));
		}
		int firstGenerationCapacity = ledger.joinTableCapacity();
		assertTrue(firstGenerationCapacity > 16, "The fixture must cross the initial table's load threshold");

		ledger.candidateReleased(1);
		ledger.candidateRetained(100);
		for (int index = 0; index < 24; index++) {
			int rightCandidateId = index + 101;
			ledger.candidateRetained(rightCandidateId);
			assertTrue(ledger.recordJoin(2_000 + index, 100, rightCandidateId, "hash"));
		}

		assertAll(
				() -> assertEquals(24, ledger.liveEntryCount()),
				() -> assertEquals(firstGenerationCapacity, ledger.joinTableCapacity(),
						"A released generation must be compacted into reusable primitive capacity before growth"));
	}
}
